					dispatch.Assigns[dispatch.AssignsLen].GenRoute()
				}
			}
			if !fallbackAdded && dispatch.AssignsLen < MAXASSIGNS {
				dispatch.Assigns[dispatch.AssignsLen].AddShip(total_ship+orderIdx, oris[orderIdx], dess[orderIdx])
				dispatch.Assigns[dispatch.AssignsLen].GenRoute()
				if dispatch.Assigns[dispatch.AssignsLen].Cost >= 0 {
					dispatch.AssignsLen++
				} else {
					dispatch.Assigns[dispatch.AssignsLen].RemoveShip(total_ship + orderIdx)
					dispatch.Assigns[dispatch.AssignsLen].GenRoute()
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch
}
